from pathlib import Path
path = Path('resources/js/Components/Assessments/AssessmentSummary.vue')
text = path.read_text(encoding='utf-8-sig')
script_end = text.split('</script>', 1)
rest = script_end[1] if len(script_end) > 1 else ''
new_script = """<script setup>\nimport { computed, ref, watch } from 'vue';\n\nconst { assessments, schoolYear } = defineProps({\n    assessments: {\n        type: Array,\n        default: () => [],\n    },\n    schoolYear: {\n        type: Object,\n        default: null,\n    },\n});\n\nconst selectedSection = ref('all');\n\nconst sectionOptions = computed(() => {\n    const map = new Map();\n\n    assessments.forEach((assessment) => {\n        const section = assessment.section;\n        const sectionKey = section?.id ? String(section.id) : 'unassigned';\n        if (map.has(sectionKey)) {\n            return;\n        }\n\n        if (section?.id) {\n            const grade = section.grade_level?.grade_level;\n            const name = section.section_name || 'Section';\n            const label = grade ? `${grade} · ${name}` : name;\n            map.set(sectionKey, { id: sectionKey, label });\n            return;\n        }\n\n        map.set(sectionKey, { id: 'unassigned', label: 'Unassigned section' });\n    });\n\n    return [{ id: 'all', label: 'All sections' }, ...map.values()];\n});\n\nwatch(\n    () => sectionOptions.value.map((option) => option.id),\n    (ids) => {\n        if (!ids.includes(selectedSection.value)) {\n            selectedSection.value = 'all';\n        }\n    },\n    { immediate: true }\n);\n\nconst filteredAssessments = computed(() => {\n    const selection = selectedSection.value;\n\n    if (!selection || selection === 'all') {\n        return assessments;\n    }\n\n    if (selection === 'unassigned') {\n        return assessments.filter((assessment) => !assessment.section?.id);\n    }\n\n    return assessments.filter((assessment) => String(assessment.section?.id) === selection);\n});\n</script>\n"""
path.write_text(new_script + rest, encoding='utf-8-sig')
